// GET /api/posts?limit=20&after=<cursor>

// --- Cursor helpers ---

// Encode a {created_at, id} pair into an opaque base64 cursor.
function encodeCursor(row) {
    const payload = JSON.stringify({
        created_at: row.created_at instanceof Date
            ? row.created_at.toISOString()
            : row.created_at,
        id: row.id,
    });
    return Buffer.from(payload, 'utf8').toString('base64url');
}

// Decode an opaque cursor back into {created_at, id}.
// Throws on anything malformed so the caller can return a 400.
function decodeCursor(cursor) {
    let parsed;
    try {
        const json = Buffer.from(cursor, 'base64url').toString('utf8');
        parsed = JSON.parse(json);
    } catch (err) {
        throw new Error('Malformed cursor');
    }

    if (
        !parsed ||
        typeof parsed !== 'object' ||
        typeof parsed.id === 'undefined' ||
        typeof parsed.created_at === 'undefined'
    ) {
        throw new Error('Malformed cursor');
    }

    // Validate the timestamp is parseable.
    if (Number.isNaN(new Date(parsed.created_at).getTime())) {
        throw new Error('Malformed cursor');
    }

    return { created_at: parsed.created_at, id: parsed.id };
}

// --- Handler ---

async function getPosts(req, res) {
    // Clamp limit to a sane range to protect the DB.
    let limit = parseInt(req.query.limit, 10) || 20;
    limit = Math.min(Math.max(limit, 1), 100);

    const { after } = req.query;

    let sql;
    let params;

    if (after) {
        let cursor;
        try {
            cursor = decodeCursor(after);
        } catch (err) {
            return res.status(400).json({ error: 'Invalid cursor' });
        }

        // Compound (created_at, id) comparison matching ORDER BY created_at DESC, id DESC.
        // Row tuples: fetch rows that sort strictly AFTER the cursor.
        // (created_at, id) < (cursor.created_at, cursor.id)
        sql = `
            SELECT id, title, content, author_id, created_at
            FROM posts
            WHERE published = true
              AND (created_at, id) < ($1::timestamptz, $2)
            ORDER BY created_at DESC, id DESC
            LIMIT $3
        `;
        params = [cursor.created_at, cursor.id, limit + 1];
    } else {
        // First page: no cursor filter.
        sql = `
            SELECT id, title, content, author_id, created_at
            FROM posts
            WHERE published = true
            ORDER BY created_at DESC, id DESC
            LIMIT $1
        `;
        params = [limit + 1];
    }

    const result = await db.query(sql, params);

    // N+1 trick: if we got an extra row, there are more pages.
    const hasMore = result.rows.length > limit;
    const posts = hasMore ? result.rows.slice(0, limit) : result.rows;

    const nextCursor = hasMore
        ? encodeCursor(posts[posts.length - 1])
        : null;

    res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,
            limit,
        },
    });
}

module.exports = { getPosts, encodeCursor, decodeCursor };
```

## Key implementation notes

- **Row-value comparison** `(created_at, id) < ($1, $2)` is the clean way to express a compound cursor. Because the sort is `DESC, DESC`, "after the cursor" means *less than* the tuple. PostgreSQL compares tuples lexicographically: first by `created_at`, and only by `id` when timestamps tie — exactly matching the `ORDER BY`. This avoids the verbose/error-prone `created_at < $1 OR (created_at = $1 AND id < $2)` form (though that's equivalent if you prefer it).
- **`$1::timestamptz` cast** ensures the ISO string from the decoded cursor compares correctly against the column type.
- **N+1 trick** asks for `limit + 1`; the extra row is a cheap "is there a next page?" probe that never reaches the client.
- **Graceful cursor handling**: `decodeCursor` throws on bad base64, bad JSON, missing fields, or an unparseable date — all funneled to a single `400`.

## Why cursor-based pagination is superior here

1. **Performance at scale** — `OFFSET N` forces Postgres to scan and discard N rows before returning results, so deep pages get linearly slower. A cursor turns every page into an index range scan: with an index on `(created_at DESC, id DESC)`, fetching page 10,000 costs the same as page 1.
2. **No expensive `COUNT(*)`** — on large tables `COUNT(*)` scans the whole table (or index) every request. Dropping it removes a major cost; cursor pagination doesn't need a total to know if there's a next page.
3. **Stability under writes** — with OFFSET, a row inserted or deleted between requests shifts the window, causing skipped or duplicated rows. A cursor anchors to actual data values, so the result set stays consistent even as posts are added.

The trade-off: clients can only go forward/back sequentially, not jump to an arbitrary page number — which is the right trade for an infinite-scroll / "load more" feed.

For a bidirectional API you'd add a `before` cursor (flip the comparison to `>` and reverse the order, then re-sort). Let me know if you want that variant.

